function SpeakBtn({ text, lang, color }) {
  const [on, setOn] = useState(false);
  const speak = () => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.lang = lang; u.rate = 0.85;
    u.onstart = () => setOn(true);
    u.onend = () => setOn(false);
    u.onerror = () => setOn(false);
    window.speechSynthesis.speak(u);
  };
  return (
    <button onClick={speak} style={{
      background: on ? color : "#fff",
      border: "2px solid " + color,
      borderRadius: "50%", width:34, height:34,
      cursor:"pointer", display:"flex", alignItems:"center",
      justifyContent:"center", flexShrink:0, transition:"all 0.2s",
      boxShadow: on ? "0 0 0 3px " + color + "33" : "none",
    }}>
      {on
        ? <svg width="13" height="13" viewBox="0 0 24 24" fill={on?"#fff":color}><rect x="6" y="4" width="4" height="16" rx="1"/><rect x="14" y="4" width="4" height="16" rx="1"/></svg>
        : <svg width="13" height="13" viewBox="0 0 24 24" fill={color}><polygon points="5,3 19,12 5,21"/></svg>
      }
    </button>
  );
}

